        OllamaChatResponse ollamaChatResponse =
                ollamaClient.chat(OllamaChatRequest.builder().build());

        assertThat(ollamaChatResponse.getMessage().getContent())
                .endsWith(mockWebServer.getPort() + "/additional/api/chat");
