import static dev.langchain4j.model.ollama.OllamaJsonUtils.fromJson;
import static org.assertj.core.api.Assertions.assertThat;

import org.junit.jupiter.api.Test;

class RunningOllamaModelTest {

    @Test
    void should_deserialize_context_length() {
        String json = """
                {
                  "models": [
                    {
                      "name": "llama3:latest",
                      "model": "llama3:latest",
                      "size": 123456789,
                      "digest": "abc123",
                      "expires_at": "2024-09-22T16:33:28.1102672+02:00",
                      "size_vram": 123456789,
                      "context_length": 4096
                    }
                  ]
                }
                """;

        RunningModelsListResponse response = fromJson(json, RunningModelsListResponse.class);

        assertThat(response.getModels()).hasSize(1);
        RunningOllamaModel model = response.getModels().get(0);
        assertThat(model.getContextLength()).isEqualTo(4096L);
    }
}

